import "server-only"
import { EncryptJWT, jwtDecrypt } from "jose"

const encodedKey = Buffer.from(process.env.SESSION_SECRET!, "hex")

type SessionPayload = {
  access_token: string
  refresh_token?: string
  expires_at: number
}

export async function encryptSession(payload: SessionPayload) {
  return new EncryptJWT(payload)
    .setProtectedHeader({ alg: "dir", enc: "A256GCM" })
    .setIssuedAt()
    .setExpirationTime("7d")
    .encrypt(encodedKey)
}

export async function decryptSession(session: string | undefined = "") {
  try {
    const { payload } = await jwtDecrypt<SessionPayload>(session, encodedKey)
    return payload
  } catch {
    return null
  }
}

import { NextRequest } from "next/server"

// Derive the site origin from the incoming request instead of an env var,
// so the OAuth redirect always targets the domain the user is actually on.
export function getRequestOrigin(request: NextRequest): string {
  const host =
    request.headers.get("x-forwarded-host") ??
    request.headers.get("host") ??
    "localhost:3000"
  const proto =
    request.headers.get("x-forwarded-proto") ??
    (host.startsWith("localhost") || host.startsWith("127.") ? "http" : "https")
  return `${proto}://${host}`
}

export function getRedirectUri(request: NextRequest): string {
  return `${getRequestOrigin(request)}/api/auth/callback`
}

