export default function OnboardingWizard(props: WizardProps) {
  const [step, setStep] = useState<number | null>(null);
  const [menuOpen, setMenuOpen] = useState(false);

  const isOpen = step !== null;
  const isLast = step === SCREENS.length - 1;

  const open = () => {
    setStep(0);
    setMenuOpen(false);
  };

  const close = () => {
    setStep(null);
    setMenuOpen(false);
  };

  const goNext = () => {
    setStep((s) => (s === null || s >= SCREENS.length - 1 ? s : s + 1));
  };

  const goBack = () => {
    setStep((s) => {
      if (s === null) return s;
      if (s === 0) return null;
      return s - 1;
    });
  };

  const jumpTo = (index: number) => {
    setStep(index);
    setMenuOpen(false);
  };

  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.altKey && e.key.toLowerCase() === "s") {
        e.preventDefault();
        jumpTo(SCREENS.length - 1);
        return;
      }
      if (e.key.toLowerCase() === "a") {
        e.preventDefault();
        goNext();
      } else if (e.key.toLowerCase() === "b") {
        e.preventDefault();
        goBack();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen]);

  return (
    <div className={styles.launcher}>
      <button type="button" className={props.isButtonBigger ? `${styles.triggerButton} ${styles.btnLarger}` : styles.triggerButton} onClick={open}>
        start adventure
      </button>
      <Link href="/dashboard" className={styles.loginLink}>
        already a trainer? login.
      </Link>

      {isOpen && (
        <div className={styles.overlay} role="dialog" aria-modal="true">
          <div className={styles.frame}>
            <div className={styles.topBar}>
              <span className={styles.topBarLogo}>HACKACHU</span>
              <button
                type="button"
                className={styles.closeButton}
                onClick={close}
                aria-label="close"
              >
                &times;
              </button>
            </div>

            <div className={styles.screenArea}>
              {step === 0 && <WelcomeScreen key="welcome" />}
              {step === 1 && <LootScreen key="loot" />}
              {step === 2 && <RulesScreen key="rules" />}
              {step === 3 && <StartScreen key="start" onStart={close} />}
            </div>

            <div className={styles.bottomBar}>
              <button
                type="button"
                className={styles.navButton}
                onClick={goBack}
              >
                &larr; back [b]
              </button>

              <div className={styles.menuWrap}>
                <button
                  type="button"
                  className={styles.menuButton}
                  onClick={() => setMenuOpen((v) => !v)}
                  aria-haspopup="true"
                  aria-expanded={menuOpen}
                >
                  menu
                </button>
                {menuOpen && (
                  <ul className={styles.menuList}>
                    {SCREENS.map((id, i) => (
                      <li key={id}>
                        <button
                          type="button"
                          className={styles.menuItem}
                          onClick={() => jumpTo(i)}
                          aria-current={step === i}
                        >
                          {SCREEN_LABELS[id]}
                        </button>
                      </li>
                    ))}
                  </ul>
                )}
              </div>

              {!isLast ? (
                <button
                  type="button"
                  className={styles.navButtonPrimary}
                  onClick={goNext}
                >
                  next [a] &rarr;
                </button>
              ) : (
                <span className={styles.navSpacer} />
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

